import{_ as o,o as t,c as s,a3 as r}from"./chunks/framework.CjquFG0V.js";const c=JSON.parse('{"title":"57. Employee Rosters","description":"","frontmatter":{"title":"57. Employee Rosters","eba":"Medical Scientists, Pharm & Psych 2021-2025","topics":["hours","rosters","on-call"]},"headers":[],"relativePath":"ebas/mspp/hours-of-work/57-employee-rosters.md","filePath":"ebas/mspp/hours-of-work/57-employee-rosters.md"}'),n={name:"ebas/mspp/hours-of-work/57-employee-rosters.md"};function a(i,e,p,l,g,h){return t(),s("div",null,[...e[0]||(e[0]=[r('<h1 id="_57-employee-rosters" tabindex="-1">57. Employee Rosters <a class="header-anchor" href="#_57-employee-rosters" aria-label="Permalink to &quot;57. Employee Rosters&quot;">​</a></h1><p><strong>57.1</strong> Rosters</p><p><strong>a.</strong> A roster setting out all relevant information including:</p><p><strong>(i)</strong> Employees’ normal working hours,</p><p><strong>(ii)</strong> Starting and finishing times,</p><p><strong>(iii)</strong> Times on call, and</p><p><strong>(iv)</strong> Time off duty; shall be posted at least 28 days before it comes into operation in a conspicuous and readily accessible place.</p><p><strong>b.</strong> The roster shall not change without at least fourteen days&#39; notice of a change in roster except in the case of sickness or other emergency, subject to subclause 57.2 below.</p><p><strong>c.</strong> Nothing in this clause precludes an Employer also issuing the roster or the on- call roster in electronic form.</p><p><strong>57.2</strong> Change of Roster</p><p><strong>a.</strong> Where an Employer changes the Employee’s roster once set in accordance with subclause 57.1a (other than as excepted in subclause 57.1b) the Change of Roster Allowance will apply in relation to each change as follows:</p><p><strong>(i)</strong> 7 days or less notice; The higher Change of Roster allowance as described in <a href="/eba/ebas/mspp/schedules/2-rates-of-pay-and-allowances.html">Schedule 2</a>.</p><p><strong>(ii)</strong> 8 to 14 days’ notice; The lower Change of Roster allowance as described in <a href="/eba/ebas/mspp/schedules/2-rates-of-pay-and-allowances.html">Schedule 2</a>.</p><p><strong>57.3</strong> Rostering Principles (Shift Work)</p><p><strong>a.</strong> Employers will ensure that shift work rosters are, as far as possible, fair and equitable given the 24/7 service obligation of the Employer and to have regard to the Employees’ family responsibilities, to reduce fatigue, stress and absenteeism.</p><p><strong>b.</strong> Safe Work Australia’s Guide for Managing the Risk of Fatigue at Work will be used by Employers as a guide in developing safe rosters.</p><p><strong>c.</strong> Rostering practices will seek to:</p><p><strong>(i)</strong> Minimise recall and overtime to reduce fatigue and absenteeism.</p><p><strong>(ii)</strong> Take into account health and welfare of Employees and any issues or concerns expressed by an Employee in relation to these.</p><p><strong>(iii)</strong> Subject to subclause 57.4 and the Employer’s operational requirements, minimise weekend work (including on call and recall).</p><p><strong>d.</strong> The provisions of <a href="/eba/ebas/mspp/employment/24-part-time-employment.html">clause 24</a> (Part Time Employment) and this clause 57 apply to part time Employees.</p><p><strong>57.4</strong> Rostering Protocols The following protocols will be applied in every roster:</p><p><strong>a.</strong> The rostering of two consecutive weekend days will not occur save for:</p><p><strong>(i)</strong> exceptional circumstances, or</p><p><strong>(ii)</strong> as per subclause 57.5 (Roster Exemption Agreement) below.</p><p><strong>b.</strong> RDOs shall be rostered on consecutive days at a minimum of once in each fortnight.</p><p><strong>c.</strong> There shall be at least one weekend free of duty (including from rostered on- call) in every three week period. Before the weekend free of duty an Employee will not be rostered past 9 pm (9.30 pm for Goulburn Valley Health) on the Friday immediately before the weekend an Employee is rostered to work on one or both days.</p><p><strong>d.</strong> Night shifts will be rostered so an Employee works no more than 40 hours in a maximum 5 day period. Night shift will not be rostered in consecutive blocks except in the case of a permanent night shift Employee, who is an Employee who has requested and works permanent night shifts. In this subclause ‘Permanently Working’ shall mean working for any period in excess of four consecutive weeks.</p><p><strong>e.</strong> Shifts will not be rostered to commence before 6.00am on any day following a day of no duty (Leave, RDO, ADO etc.)</p><p><strong>f.</strong> Two consecutive RDO/ADO days will be rostered immediately following any period of night duty.</p><p><strong>57.5</strong> Rostering Protocols Exemption Agreement</p><p><strong>a.</strong> An Employee may request and an Employer may agree to a roster pattern that is inconsistent with the rostering protocols at subclauses 57.4a and / or 57.4c where:</p><p><strong>(i)</strong> the request is at the initiative of the Employee, providing that Employee has no less than 6 months employment with the Employer;</p><p><strong>(ii)</strong> the changed roster is safe; and</p><p><strong>(iii)</strong> there is a written Rostering Protocols Exemption Agreement in the form prescribed by <a href="/eba/ebas/mspp/schedules/15-rostering-protocols-exemption-agreement.html">Schedule 15</a>.</p><p><strong>b.</strong> An Employee is entitled to be represented, including by the Union, at any time.</p><p><strong>c.</strong> An Employee may unilaterally withdraw from the Roster Exemption Agreement by giving notice to the Employer in writing.</p><p><strong>d.</strong> An Employee who withdraws from a Roster Exemption Agreement will revert to a roster without exemptions from the requirements of subclause 57.4a. and 57.5c. The Employer may determine the date of effect of the termination of the Rostering Protocols Exemption Agreement provided that the date may not be more than 28 days after the date of notice by the Employee.</p><p><strong>e.</strong> An Employee who has withdrawn from a Roster Exemption Agreement may at any time afterwards request another Rostering Protocols Exemption Agreement.</p><p><strong>f.</strong> A Rostering Protocols Exemption Agreement must comply with the provisions of this clause to make any such arrangement compliant with subclause 57.4.</p><p><strong>g.</strong> An Employer cannot request or direct an Employee to enter into (or agree) to a Rostering Protocols Exemption Agreement in accordance with this clause.</p><p><strong>57.6</strong> Rest Breaks Between Rostered Shifts</p><p><strong>a.</strong> The roster or rosters shall be drawn up so as to provide:</p><p><strong>(i)</strong> until the day clause (ii) becomes operational --- at least eight hours off duty between successive ordinary hour shifts, and</p><p><strong>(ii)</strong> from the date of the first roster posted following 4 weeks from the date this Agreement comes into operation --- at least ten hours off duty between successive ordinary hour shifts.</p><p>Plain language terms: rostering, shift roster, duty roster.</p>',46)])])}const d=o(n,[["render",a]]);export{c as __pageData,d as default};
